COMMENT ON TABLE "tasks"."Tickets" IS 'Заявки, хранящиеся в системе';
COMMENT ON COLUMN "tasks"."Tickets"."title" IS 'Название задачи в системе';
COMMENT ON COLUMN "tasks"."Tickets"."description" IS 'Описание задачи';
COMMENT ON COLUMN "tasks"."Tickets"."type_id" IS 'Тип задачи';
COMMENT ON COLUMN "tasks"."Tickets"."status_id" IS 'Статус задачи';
