COMMENT ON COLUMN "tasks"."Tickets"."updated_at" IS 'Время последнего обновления задачи';
COMMENT ON COLUMN "tasks"."Tickets"."updated_by" IS 'Последний обновивший задачи';
COMMENT ON COLUMN "tasks"."Tickets"."responsible_id" IS 'Ответственный за задачу';
COMMENT ON TABLE "tasks"."ConnectedTickets" IS 'Связь задач';
COMMENT ON TABLE "tasks"."Comments" IS 'Комментарии, оставленные под задачами';
COMMENT ON COLUMN "tasks"."Comments"."created_by" IS 'Создатель комментария';
COMMENT ON COLUMN "tasks"."Comments"."created_at" IS 'Время создания комментария';
COMMENT ON COLUMN "tasks"."Comments"."updated_at" IS 'Время последнего обновления комментария';
COMMENT ON COLUMN "tasks"."Comments"."contents" IS 'Текст комментария';
COMMENT ON TABLE "tasks"."Reactions" IS 'Реакции';
COMMENT ON COLUMN "tasks"."Reactions"."name" IS 'Наименование реакции';
COMMENT ON COLUMN "tasks"."Reactions"."picture" IS 'Картинка реакции, мелкоформатная';
COMMENT ON TABLE "tasks"."CommentsReactions" IS 'Реакциии на комменты';

-- auth
ALTER TABLE "auth"."RolePermissions" ADD FOREIGN KEY ("role_id") REFERENCES "auth"."Roles" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "auth"."RolePermissions" ADD FOREIGN KEY ("permission_id") REFERENCES "auth"."Permissions" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "auth"."Accounts" ADD FOREIGN KEY ("role_id") REFERENCES "auth"."Roles" ("id") ON DELETE RESTRICT ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "auth"."Sessions" ADD FOREIGN KEY ("account_id") REFERENCES "auth"."Accounts" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;

-- profiles / hrm
ALTER TABLE "profiles"."Profiles" ADD FOREIGN KEY ("account_id") REFERENCES "auth"."Accounts" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "hrm"."Employees" ADD FOREIGN KEY ("account_id") REFERENCES "profiles"."Profiles" ("account_id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;

-- crm
ALTER TABLE "crm"."Clients" ADD FOREIGN KEY ("ceo_id") REFERENCES "auth"."Accounts" ("id") ON DELETE SET NULL ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
