ALTER TABLE "crm"."Sites" ADD FOREIGN KEY ("responsible_id") REFERENCES "crm"."Representatives" ("account_id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
