ALTER TABLE "crm"."SitesProducts" ADD FOREIGN KEY ("product_id") REFERENCES "crm"."Products" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;

-- nri
ALTER TABLE "nri"."ProductEquipment_Types" ADD FOREIGN KEY ("product_id") REFERENCES "crm"."Products" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "nri"."ProductEquipment_Types" ADD FOREIGN KEY ("equipment_type_id") REFERENCES "nri"."Equipment_Types" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "nri"."Equipment" ADD FOREIGN KEY ("type_id") REFERENCES "nri"."Equipment_Types" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "nri"."Equipment" ADD FOREIGN KEY ("site_id") REFERENCES "crm"."Sites" ("id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;

-- tasks
ALTER TABLE "tasks"."Tickets" ADD FOREIGN KEY ("type_id") REFERENCES "tasks"."Type" ("id") ON DELETE RESTRICT ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "tasks"."Tickets" ADD FOREIGN KEY ("status_id") REFERENCES "tasks"."Status" ("id") ON DELETE RESTRICT ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "tasks"."Tickets" ADD FOREIGN KEY ("criticality_id") REFERENCES "tasks"."Criticality" ("id") ON DELETE RESTRICT ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
