ALTER TABLE "tasks"."Tickets" ADD FOREIGN KEY ("site_id") REFERENCES "crm"."Sites" ("id") ON DELETE SET NULL ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "tasks"."Tickets" ADD FOREIGN KEY ("product_id") REFERENCES "crm"."Products" ("id") ON DELETE SET NULL ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "tasks"."Tickets" ADD FOREIGN KEY ("created_by") REFERENCES "profiles"."Profiles" ("account_id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "tasks"."Tickets" ADD FOREIGN KEY ("updated_by") REFERENCES "profiles"."Profiles" ("account_id") ON DELETE CASCADE ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
ALTER TABLE "tasks"."Tickets" ADD FOREIGN KEY ("responsible_id") REFERENCES "profiles"."Profiles" ("account_id") ON DELETE SET NULL ON UPDATE NO ACTION DEFERRABLE INITIALLY IMMEDIATE;
